<?php $document = $document ?? []; $vault = $vault ?? []; $history = $history ?? []; $documentTypes = $documentTypes ?? []; ?>
<div class="page-header"><h1>Document Vault: <?= escapeHtml($document['document_number'] ?? '') ?></h1><a href="/export-documents" class="btn btn-outline-secondary">Back</a></div>
<div class="card mb-3"><div class="card-body"><div class="row"><div class="col-md-3"><strong>Type:</strong> <?= escapeHtml($document['document_type'] ?? '') ?></div><div class="col-md-3"><strong>Buyer:</strong> <?= escapeHtml($document['buyer_name'] ?? '') ?></div><div class="col-md-3"><strong>Date:</strong> <?= escapeHtml($document['document_date'] ?? '') ?></div><div class="col-md-3"><strong>Status:</strong> <?= statusBadge((int) ($document['status'] ?? 0)) ?></div></div></div></div>
<div class="card mb-3"><div class="card-body"><h5>Upload Document</h5><form method="post" action="/export-documents/<?= (int) ($document['id'] ?? 0) ?>/upload" enctype="multipart/form-data" class="row g-3"><?= csrfToken() ?><div class="col-md-4"><select name="attachment_type" class="form-select"><?php foreach ($documentTypes as $type => $label): ?><option value="<?= escapeHtml($type) ?>"><?= escapeHtml($label) ?></option><?php endforeach; ?></select></div><div class="col-md-6"><input type="file" name="document_file" class="form-control" required></div><div class="col-md-2"><button class="btn btn-primary w-100">Upload</button></div></form></div></div>
<div class="row"><?php foreach ($vault as $type => $group): ?><div class="col-md-6 mb-3"><div class="card h-100"><div class="card-header"><strong><?= escapeHtml($group['label']) ?></strong></div><div class="card-body"><?php if (empty($group['files'])): ?><div class="text-muted">No documents attached.</div><?php endif; ?><?php foreach ($group['files'] as $file): ?><div class="d-flex justify-content-between align-items-center border-bottom py-2"><div><div><?= escapeHtml($file['original_name']) ?></div><small class="text-muted">Version: <?= (int) $file['id'] ?> · <?= escapeHtml($file['created_at']) ?> · <?= escapeHtml(trim(($file['first_name'] ?? '') . ' ' . ($file['last_name'] ?? ''))) ?></small></div><div><a href="/export-documents/attachment/<?= (int) $file['id'] ?>/preview" class="btn btn-sm btn-outline-secondary" target="_blank">Preview</a> <a href="/export-documents/attachment/<?= (int) $file['id'] ?>/download" class="btn btn-sm btn-outline-primary">Download</a></div></div><?php endforeach; ?></div></div></div><?php endforeach; ?></div>
<div class="card"><div class="card-body"><h5>Document Status</h5><form method="post" action="/export-documents/<?= (int) ($document['id'] ?? 0) ?>/status" class="row g-2"><?= csrfToken() ?><div class="col-md-3"><input type="number" name="status" class="form-control" value="<?= (int) ($document['status'] ?? 0) ?>"></div><div class="col-md-7"><input name="remarks" class="form-control" placeholder="Status remarks"></div><div class="col-md-2"><button class="btn btn-primary w-100">Update</button></div></form><?php foreach ($history as $entry): ?><div class="small text-muted mt-2"><?= escapeHtml($entry['created_at']) ?>: <?= (int) $entry['new_status'] ?> <?= escapeHtml($entry['remarks'] ?? '') ?></div><?php endforeach; ?></div></div>